1	export type Cell = [number, number];
2	
3	type CellKey = string;
4	
5	const encodeCell = ([x, y]: Cell): CellKey => `${x},${y}`;
6	
7	const decodeCell = (key: CellKey): Cell => {
8	  const [x, y] = key.split(",");
9	  return [Number(x), Number(y)];
10	};
11	
12	const neighborOffsets: ReadonlyArray<[number, number]> = [
13	  [-1, -1], [-1, 0], [-1, 1],
14	  [ 0, -1],          [ 0, 1],
15	  [ 1, -1], [ 1, 0], [ 1, 1],
16	];
17	
18	const survives = (wasAlive: boolean, liveNeighbors: number): boolean =>
19	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
20	
21	export const nextGeneration = (cells: Cell[]): Cell[] => {
22	  const aliveKeys = new Set(cells.map(encodeCell));
23	  const neighborCounts = new Map<CellKey, number>();
24	
25	  for (const [x, y] of cells) {
26	    for (const [dx, dy] of neighborOffsets) {
27	      const key = encodeCell([x + dx, y + dy]);
28	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
29	    }
30	  }
31	
32	  const result: Cell[] = [];
33	  for (const [key, count] of neighborCounts) {
34	    if (survives(aliveKeys.has(key), count)) {
35	      result.push(decodeCell(key));
36	    }
37	  }
38	  return result;
39	};
40

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) stable across generations (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should kill an overpopulated cell with more than 3 live neighbors", () => {
20	    // Center cell (1,1) has 4 live neighbors at (0,0),(0,1),(0,2),(2,1)
21	    const cells: [number, number][] = [[1, 1], [0, 0], [0, 1], [0, 2], [2, 1]];
22	    const result = nextGeneration(cells);
23	    expect(result).not.toContainEqual([1, 1]);
24	  });
25	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
26	    // L-shape: dead cell (1,1) has 3 live neighbors at (0,0),(1,0),(0,1)
27	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
28	    const result = nextGeneration(cells);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
32	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
33	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
34	    const result = nextGeneration(vertical);
35	    expect(result.sort()).toEqual(horizontal.sort());
36	  });
37	  it("should handle negative coordinates correctly", () => {
38	    // Block at negative coordinates - still life
39	    const negativeBlock: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
40	    const result = nextGeneration(negativeBlock);
41	    expect(result.sort()).toEqual(negativeBlock.sort());
42	  });
43	});
